// DRAFT — run once for all items from Load all (0..N state rows); always output 3 repo targets.
// $('Data Table - Load all state rows').all() remains valid for Decide on this execution path.
const repos = [
  { ownerRepo: 'mrhz1973/control-plane', stateKey: 'github:mrhz1973/control-plane:last_commit_sha', sourceRepo: 'mrhz1973/control-plane' },
  { ownerRepo: 'mrhz1973/dev-method', stateKey: 'github:mrhz1973/dev-method:last_commit_sha', sourceRepo: 'mrhz1973/dev-method' },
  { ownerRepo: 'mrhz1973/cursor-coordinate-converter', stateKey: 'github:mrhz1973/cursor-coordinate-converter:last_commit_sha', sourceRepo: 'mrhz1973/cursor-coordinate-converter' }
];
return repos.map((r) => ({ json: r }));

// Pair by item index: Emit (3) + HTTP response for same repo.
const target = $('Emit watched repos (3)').item.json;
const resp = $input.item.json;
const commit = Array.isArray(resp) ? resp[0] : resp;
const sha = commit?.sha || '';
const rawMessage = commit?.commit?.message || 'no commit message';
const message = rawMessage.split('\n')[0];
const url = commit?.html_url || 'no URL';
return {
  json: {
    stateKey: target.stateKey,
    currentSha: sha,
    shortSha: sha ? sha.substring(0, 7) : '',
    message,
    url,
    sourceRepo: target.sourceRepo,
    ownerRepo: target.ownerRepo
  }
};

// Join all Prepare items (3 repos) with state snapshot; missing Data Table row => storedValue ''.
const prepareItems = $('Prepare latest commit event').all();
const stateRows = $('Data Table - Load all state rows').all().map((entry) => entry.json);
return prepareItems.map((item) => {
  const latest = item.json;
  const row = stateRows.find((r) => r.key === latest.stateKey);
  const storedValue = row?.value || '';
  const isNew = Boolean(latest.currentSha && latest.currentSha !== storedValue);
  return {
    json: {
      ...latest,
      previousSha: storedValue || '',
      isNew,
      hadStateRow: Boolean(row?.key)
    }
  };
});

const latest = $('Decide Data Table dedupe').item.json;
const previous = latest.previousSha ? latest.previousSha.substring(0, 7) : 'none';
const title = latest.message || 'no commit message';
return {
  json: {
    text: `CONTROL PLANE scheduled poll commit notification\nRepo: ${latest.sourceRepo}\nNew commit: ${latest.shortSha}\nPrevious: ${previous}\nMessage: ${title}\nURL: ${latest.url}`
  }
};

return {
  json: {
    status: 'duplicate_skip',
    reason: 'Latest commit already stored in control_plane_state for this repo key',
    stateKey: $json.stateKey,
    sourceRepo: $json.sourceRepo,
    currentSha: $json.currentSha,
    previousSha: $json.previousSha
  }
};
